Javascript.validate:
            var ec = null;
            var partyName = Services.getValue(PartyName.dataBinding);
            if ( !CaseManUtils.isBlank(partyName) )
            {
                var countChars = 0;
                var countWildCards = 0;
                for ( var i = 0, l = partyName.length; i < l; i++ )
                {
                    var tempChar = partyName.charAt(i);
                    if ( tempChar == "%" ) countWildCards++;
                    else if ( /[A-Za-z]/.test(tempChar) ) countChars++;
                }

                if ( countChars < 2 )
                {
                    ec = ErrorCode.getErrorCode("CaseMan_AtLeastTwoAlphaCharacters_Msg");
                }
                else if ( countWildCards > 2 )
                {
                    ec = ErrorCode.getErrorCode("CaseMan_MaximumOfTwoWildCards_Msg");
                }
            }
            return ec;

